-- 基于 52Poke 树果总表与单个树果页面生成的主线树果百科种子。
-- 参考：https://wiki.52poke.com/wiki/树果
ON CONFLICT (code) DO UPDATE
SET name = EXCLUDED.name,
    description = EXCLUDED.description,
    color_code = EXCLUDED.color_code,
    firmness_code = EXCLUDED.firmness_code,
    size_cm = EXCLUDED.size_cm,
    smoothness = EXCLUDED.smoothness,
    spicy = EXCLUDED.spicy,
    dry = EXCLUDED.dry,
    sweet = EXCLUDED.sweet,
    bitter = EXCLUDED.bitter,
    sour = EXCLUDED.sour,
    natural_gift_type_id = EXCLUDED.natural_gift_type_id,
    natural_gift_power = EXCLUDED.natural_gift_power,
    sorting_order = EXCLUDED.sorting_order,
    enabled = EXCLUDED.enabled,
    version = catalog.berry_definition.version + 1;

